INSERT INTO metrics (id, name_ru, name_short_ru, metric_type, data_type, formula, dependencies, tags, is_core, is_active, is_hidden_in_ui, is_test, decimal_places, aggregation_fn, fill_ok, calc_ok, is_collect_ok, is_calc_ok, category, sort_order, description)
VALUES ('cr_stage_new_to_taken', 'CR Новая → Взял в работу (перв.)', 'CR Нова→Взял (п)', 'calculated', 'percent', '[stage_new_to_taken_num] / [stage_new_denom] * 100', ARRAY['stage_new_to_taken_num','stage_new_denom'], '{}', false, true, false, false, 1, 'avg', false, true, false, true, 'Конверсии стадий', 1021, 'Стадии «Новая»/«Взял в работу» существуют только в воронках ЧЛ+ЮЛ (обе is_repeat=false) — см. миграцию. Знаменатель = сделки, впервые попавшие в стадию «Новая» в периоде отчёта (sa.deal_events, MIN(event_at)). Числитель = те из них, что когда-либо ПОСЛЕ этого достигли «Взял в работу» (не только в периоде). Данные deal_events — с 03.04.2026, раньше — честный null.')
ON CONFLICT (id) DO UPDATE SET name_ru = EXCLUDED.name_ru, name_short_ru = EXCLUDED.name_short_ru, metric_type = EXCLUDED.metric_type, data_type = EXCLUDED.data_type, formula = EXCLUDED.formula, dependencies = EXCLUDED.dependencies, is_hidden_in_ui = EXCLUDED.is_hidden_in_ui, aggregation_fn = EXCLUDED.aggregation_fn, category = EXCLUDED.category, sort_order = EXCLUDED.sort_order, is_active = EXCLUDED.is_active, is_collect_ok = EXCLUDED.is_collect_ok, is_calc_ok = EXCLUDED.is_calc_ok, description = EXCLUDED.description;

INSERT INTO metrics (id, name_ru, name_short_ru, metric_type, data_type, formula, dependencies, tags, is_core, is_active, is_hidden_in_ui, is_test, decimal_places, aggregation_fn, fill_ok, calc_ok, is_collect_ok, is_calc_ok, category, sort_order, description)
VALUES ('cr_stage_new_to_taken_repeat', 'CR Новая → Взял в работу (повт.)', 'CR Нова→Взял (пв)', 'calculated', 'percent', NULL, '{}', '{}', false, true, false, false, 1, 'avg', false, true, false, true, 'Конверсии стадий', 1022, 'Структурно ВСЕГДА null: стадии «Новая»/«Взял в работу» (основной путь ЧЛ/ЮЛ) физически не существуют в повторных воронках (B2C/B2B, is_repeat=true) — Bitrix stage_id не пересекаются между пайплайнами. Метрика заведена для полноты тройки (перв./повт./все) по требованию задачи; формулы намеренно нет (is_calc_ok=false) — если повторные воронки когда-нибудь заведут аналогичные стадии, потребуется отдельная миграция.')
