VALUES ('stage_price_lower_denom_primary', 'Впервые «Есть цена дешевле» за период, первичные (служебная)', NULL, 'external', 'int', NULL, '{}', '{}', false, true, true, false, 0, 'sum', false, false, true, false, 'Конверсии стадий', 1063, 'Сделки, ВПЕРВЫЕ (MIN(event_at) по sa.deal_events) попавшие в стадию «Есть цена дешевле, запросил предложение лучше» (стадии объединены по названию через ILIKE — сейчас UC_PU4HM2 (ЧЛ) и C1:11 (ЮЛ), см. features/reports/engine/priceObjectionConversion.ts) в периоде отчёта. Инжектится сервером, не через buildCollectedSQL. Первичная воронка (funnels.is_repeat=false).')
