VALUES ('stage_price_lower_denom_repeat', 'Впервые «Есть цена дешевле» за период, повторные (служебная)', NULL, 'external', 'int', NULL, '{}', '{}', false, true, true, false, 0, 'sum', false, false, true, false, 'Конверсии стадий', 1064, 'Сделки, ВПЕРВЫЕ (MIN(event_at) по sa.deal_events) попавшие в стадию «Есть цена дешевле, запросил предложение лучше» (стадии объединены по названию через ILIKE — сейчас UC_PU4HM2 (ЧЛ) и C1:11 (ЮЛ), см. features/reports/engine/priceObjectionConversion.ts) в периоде отчёта. Инжектится сервером, не через buildCollectedSQL. Повторная воронка (funnels.is_repeat=true) — на момент миграции 064 стадий с таким названием в повторных воронках нет (см. worklog), поэтому значение всегда 0, но код запрашивает по-настоящему (funnels.is_repeat), не хардкодит — если Bitrix заведёт такую стадию в B2C/B2B, метрика заработает сама.')
